const items = [];
const cutoff = new Date();
cutoff.setDate(cutoff.getDate() - 3);

function detectCountry(url, title) {
  const text = (url + ' ' + title).toLowerCase();
  if (text.includes('hk') || text.includes('hongkong') || text.includes('hong-kong') ||
      text.includes('hkma') || text.includes('sfc.hk') || text.includes('hkex')) {
    return 'Hong Kong';
  }
  if (text.includes('china') || text.includes('beijing') || text.includes('shanghai') ||
      text.includes('shenzhen') || text.includes('csrc') || text.includes('pboc') ||
      text.includes('samr') || text.includes('.cn')) {
    return 'China';
  }
  return 'Singapore';
}

for (const item of $input.all()) {
  const data = item.json;
  const results = data.results || (data.data && data.data.results) || (Array.isArray(data) ? data : null);
  if (!results || !Array.isArray(results)) continue;

  for (const r of results) {
    if (!r.url || !r.title || r.title.length < 15) continue;

    let articleDate = new Date();
    if (r.published_date) {
      const d = new Date(r.published_date);
      if (!isNaN(d.getTime())) articleDate = d;
    }
    if (articleDate < cutoff) continue;

    let hostname = 'unknown';
    try { hostname = new URL(r.url).hostname.replace('www.', ''); } catch(e) {}

    // Clean source name
    const sourcePart = hostname.split('.')[0];
    const sourceName = sourcePart.split('-')
      .map(w => w.charAt(0).toUpperCase() + w.slice(1))
      .join(' ');
    const sourceId = sourcePart.toLowerCase();

    // Hash — URL + title (dedup ke liye)
    const str = r.url + '|' + r.title;
    let hash = 2166136261;
    for (let i = 0; i < str.length; i++) {
      hash ^= str.charCodeAt(i);
      hash = (hash * 16777619) >>> 0;
    }

    // urlHash — URL only (MongoDB ke liye)
    const urlStr = r.url;
    let urlHash = 2166136261;
    for (let i = 0; i < urlStr.length; i++) {
      urlHash ^= urlStr.charCodeAt(i);
      urlHash = (urlHash * 16777619) >>> 0;
    }

    const country = detectCountry(r.url, r.title);

    items.push({ json: {
      title:       (r.title || '').trim().substring(0, 200),
      raw_summary: (r.content || r.snippet || '').substring(0, 600).trim(),
      url:         r.url,
      source:      sourceName,
      sourceId:    sourceId,
      sourceType:  hostname,
      date:        articleDate.toISOString().split('T')[0],
      hash:        hash.toString(16).padStart(8, '0'),
      urlHash:     urlHash.toString(16).padStart(8, '0'),
      type:        'news',
      country:     country,
      fetched_at:  new Date().toISOString()
    }});
  }
}

console.log(`Tavily items after 3d filter: ${items.length}`);
return items.length > 0 ? items : [{ json: { _skip: true, reason: 'no results' } }];

const output = [];
const staticData = $getWorkflowStaticData('global');
let seenHashes = staticData.seenHashes || {};
let seenTimestamps = staticData.seenTimestamps || {};
const cutoff = Date.now() - (45 * 24 * 60 * 60 * 1000);

for (const h in seenTimestamps) {
  if (seenTimestamps[h] < cutoff) {
    delete seenHashes[h];
    delete seenTimestamps[h];
  }
}

for (const item of $input.all()) {
  const data = item.json;
  const hash = data.hash;
  if (seenHashes[hash]) {
    output.push({ json: { ...data, _duplicate: true } });
  } else {
    seenHashes[hash] = true;
    seenTimestamps[hash] = Date.now();
    output.push({ json: { ...data, _duplicate: false } });
  }
}

staticData.seenHashes = seenHashes;
staticData.seenTimestamps = seenTimestamps;

return output;

const crypto = require('crypto');

const output = [];

function slugify(text) {
  return String(text || '')
    .toLowerCase()
    .trim()
    .replace(/\s+/g, '-')
    .replace(/[^\w-]+/g, '')
    .replace(/--+/g, '-')
    .replace(/^-+/, '')
    .replace(/-+$/, '');
}

function normalizeUrl(rawUrl) {
  try {
    const u = new URL(String(rawUrl || '').trim());
    u.hash = '';
    u.host = u.host.toLowerCase();

    const dropParams = [];

    for (const [k] of u.searchParams.entries()) {
      const key = k.toLowerCase();

      if (
        key.startsWith('utm_') ||
        ['fbclid', 'gclid', 'ref', 'ref_src'].includes(key)
      ) {
        dropParams.push(k);
      }
    }

    dropParams.forEach(k => u.searchParams.delete(k));

    let s = u.toString();
    if (s.endsWith('/')) s = s.slice(0, -1);

    return s;
  } catch {
    return String(rawUrl || '').trim();
  }
}

function extractHostname(urlStr) {
  const cleanUrl = String(urlStr || '').trim();

  try {
    return new URL(cleanUrl).hostname.replace(/^www\./, '');
  } catch {}

  const match = cleanUrl.match(/^https?:\/\/(?:www\.)?([^/]+)/i);
  return match ? match[1].toLowerCase() : '';
}

function titleCaseDomain(hostname) {
  if (!hostname) return 'Unknown Source';

  const firstPart = hostname.split('.')[0];

  return firstPart
    .split('-')
    .filter(Boolean)
    .map(w => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase())
    .join(' ');
}

function getSourceInfo(d) {
  const urlStr = String(d.url || '').trim();
  const hostname = extractHostname(urlStr);

  const incomingSource = String(d.source || '').trim();
  const badSources = [
    '',
    'unknown',
    'unknown source',
    'n/a',
    'na',
    'null',
    'undefined',
  ];

  const shouldUseIncoming = !badSources.includes(incomingSource.toLowerCase());

  const sourceName = shouldUseIncoming
    ? incomingSource
    : titleCaseDomain(hostname);

  return {
    source: sourceName,
    sourceId: slugify(sourceName),
    sourceType: hostname,
  };
}

function hashUrl(urlStr) {
  return crypto
    .createHash('sha256')
    .update(normalizeUrl(urlStr))
    .digest('hex');
}

function toIsoDate(value, fallback = null) {
  if (!value) return fallback;

  const date = new Date(value);
  if (Number.isNaN(date.getTime())) return fallback;

  return date.toISOString();
}

for (const item of $input.all()) {
  const d = item.json;

  if (!d.category || d.category === 'IGNORE') continue;

  const relevanceScore = parseInt(d.relevance_score ?? d.relevanceScore, 10) || 0;
  if (relevanceScore < 50) continue;

  const urlStr = String(d.url || '').trim();
  if (!urlStr || !d.title) continue;

  const sourceInfo = getSourceInfo(d);

  output.push({
    json: {
      title: String(d.title || '').trim(),
      summary: d.summary || '',
      url: urlStr,
      urlHash: hashUrl(urlStr),
      hash: d.hash || '',
      type: d.type || 'news',
      category: d.category || 'General',
      subcategory: d.sub_category || d.subcategory || '',
      source: sourceInfo.source,
      sourceId: sourceInfo.sourceId,
      sourceType: sourceInfo.sourceType,
      country: d.country || 'Singapore',
      relevanceScore,
      aiSummary: d.relevance_reason || d.aiSummary || '',
      isPublished: true,
      publishedAt: toIsoDate(d.date || d.publishedAt, null),
      fetchedAt: toIsoDate(d.fetched_at || d.fetchedAt, new Date().toISOString()),
    },
  });
}

return output;

const saved = $input.all();
const count = saved.length;
const cats = {};
for (const item of saved) {
  const cat = item.json.category || 'Unknown';
  cats[cat] = (cats[cat] || 0) + 1;
}
const catStr = Object.entries(cats).map(([k,v])=>`${k}: ${v}`).join(', ');
console.log(`Pipeline saved ${count} articles. Categories: ${catStr}`);
return [{ json: { pipeline_done: true, saved_count: count, categories: cats, run_at: new Date().toISOString() } }];

