const output = [];
const aiItems = $input.all();

for (let i = 0; i < aiItems.length; i++) {
  const aiRaw = aiItems[i].json.output || aiItems[i].json.text || aiItems[i].json.content || '';

  const article = $('Filter Dup Accounting Tax').all()[i]?.json || {};

  let aiResult = {
    category: 'Uncategorized',
    sub_category: '',
    ai_summary: '',
    relevance_score: 0,
    relevance_reason: 'Parse error'
  };

  try {
    let clean = aiRaw.trim()
      .replace(/^```json\s*/i, '')
      .replace(/^```\s*/i, '')
      .replace(/\s*```$/i, '')
      .trim();
    aiResult = { ...aiResult, ...JSON.parse(clean) };
  } catch(e) {
    const catM    = aiRaw.match(/"category"\s*:\s*"([^"]+)"/);
    const subM    = aiRaw.match(/"sub_category"\s*:\s*"([^"]+)"/);
    const scoreM  = aiRaw.match(/"relevance_score"\s*:\s*(\d+)/);
    const sumM    = aiRaw.match(/"ai_summary"\s*:\s*"([^"]+)"/);
    const reasonM = aiRaw.match(/"relevance_reason"\s*:\s*"([^"]+)"/);
    if (catM)    aiResult.category         = catM[1];
    if (subM)    aiResult.sub_category     = subM[1];
    if (scoreM)  aiResult.relevance_score  = parseInt(scoreM[1]);
    if (sumM)    aiResult.ai_summary       = sumM[1];
    if (reasonM) aiResult.relevance_reason = reasonM[1];
  }

  aiResult.relevance_score = Math.max(0, Math.min(100, parseInt(aiResult.relevance_score) || 0));

  output.push({ json: {
    hash:             article.hash,
    date:             article.date || '',
    title:            article.title,
    summary:          aiResult.ai_summary,
    url:              article.url,
    source:           article.source || '',
    category:         aiResult.category,
    sub_category:     aiResult.sub_category || '',
    country:          article.country || 'Singapore',
    type:             'news',
    fetched_at:       article.fetched_at,
    relevance_score:  aiResult.relevance_score,
    relevance_reason: aiResult.relevance_reason
  }});
}

return output;

